// Parse Znuny TicketGet response (DynamicFields=1)
// Format: { "Ticket": [{...ticket, DynamicField: [{Name, Value}]}] }
const input = $('📥 Input from Master').first().json;
const response = $input.first().json;
const ticket_id = input.ticket_id;

if (response.Error || !response.Ticket) {
  return [{
    json: {
      ticket_id, error: response.Error?.ErrorMessage || 'Ticket nicht gefunden',
      title: `Ticket ${ticket_id}`,
      wer: 'unknown', was: 'unknown', wan: new Date().toISOString(),
      priority: 'normal', status: 'unknown'
    }
  }];
}

const ticket = Array.isArray(response.Ticket) ? response.Ticket[0] : response.Ticket;

// DynamicFields: bei DynamicFields=1 liefert Znuny ein Array: [{Name, Value}]
// Fallback auf flache DynamicField_<Name> Keys (ältere API-Versionen)
const getDynField = (name) => {
  if (Array.isArray(ticket.DynamicField)) {
    const f = ticket.DynamicField.find(f => f.Name === name);
    return f && f.Value ? f.Value : null;
  }
  return ticket[`DynamicField_${name}`] || null;
};

const wer  = getDynField('ZabbixWer')  || getDynField('Wer')  || 'unknown';
const was  = getDynField('ZabbixWas')  || getDynField('Was')  || ticket.Title || 'unknown';
const wan  = getDynField('ZabbixWann') || getDynField('Wan')  || ticket.Created || new Date().toISOString();
const ref  = getDynField('ZabbixReferenz')  || null;
const komm = getDynField('ZabbixKommentar') || null;

return [{
  json: {
    ticket_id: ticket.TicketID || ticket_id,
    ticket_number: ticket.TicketNumber || `TN-${ticket_id}`,
    title: ticket.Title || `Ticket ${ticket_id}`,
    wer, was, wan,
    zabbix_referenz: ref,
    zabbix_kommentar: komm,
    priority: ticket.Priority || 'normal',
    status: ticket.State || 'new',
    queue: ticket.Queue || 'unknown',
    owner: ticket.Owner || 'unknown',
    customer_user: ticket.CustomerUserID || 'unknown'
  }
}];
